Script.Source:
String login = (String) workflow.get("login");
String email = context.runRule("Rule-Joiner-GenerateEmail", null);
workflow.put("email", email);

ProvisioningPlan plan = new ProvisioningPlan();

AccountRequest accountRequest = new AccountRequest();
accountRequest.setApplication("Active Directory");
accountRequest.setOperation(AccountRequest.Operation.Create);

AttributeRequest attrLogin = new AttributeRequest();
attrLogin.setName("sAMAccountName");
attrLogin.setValue((String) workflow.get("login"));
attrLogin.setOperation(AttributeRequest.Operation.Set);
accountRequest.add(attrLogin);

AttributeRequest attrDept = new AttributeRequest();
attrDept.setName("department");
attrDept.setValue((String) workflow.get("department"));
attrDept.setOperation(AttributeRequest.Operation.Set);
accountRequest.add(attrDept);

plan.add(accountRequest);
return plan;
